4 Parte B: UPDATE y DELETE (20 min)

4.1 Ejercicio UPDATE
-- 1. Cambiar el estado del pedido con id=3 a 'entregado'
UPDATE pedidos SET estado = 'entregado' WHERE id_pedido = 3;

-- 2. Actualizar el stock de zapatillas (id_producto=1) descontando 5 unidades
UPDATE productos SET stock = stock - 5 WHERE id_producto = 1;

-- 3. Actualizar el email del cliente con id=2
UPDATE clientes
SET email = 'nuevo_email@techstyle.cl'
WHERE id_cliente = 2;


4.2 Ejercicio DELETE (con verificación previa)
-- BUENA PRÁCTICA: Antes de DELETE, verificar con SELECT qué se eliminará
SELECT * FROM devoluciones WHERE id_devolucion = 1;

-- Luego eliminar
DELETE FROM devoluciones WHERE id_devolucion = 1;

-- Intento de DELETE que debe fallar por FK (documentar el error)
DELETE FROM clientes WHERE id_cliente = 1;
-- ¿Por qué falla? Documentar el mensaje de error.

Modificar Tablas: ALTER TABLE
-- Agregar una columna
ALTER TABLE clientes ADD COLUMN activo BOOLEAN NOT NULL DEFAULT TRUE;

-- Modificar el tipo de una columna
ALTER TABLE productos MODIFY COLUMN categoria VARCHAR(80) NOT NULL;

-- Eliminar una columna
ALTER TABLE clientes DROP COLUMN activo;

Advertencia: DROP COLUMN elimina la columna y todos sus datos permanentemente.

Índices Básicos: Acelerar los JOINs
-- Crear un índice en la columna FK (si no existe ya)
CREATE INDEX idx_pedidos_cliente    ON pedidos(id_cliente);
CREATE INDEX idx_pedidos_repartidor ON pedidos(id_repartidor);
CREATE INDEX idx_items_pedido       ON order_items(id_pedido);
CREATE INDEX idx_items_producto     ON order_items(id_producto);

-- Los índices en PK se crean automáticamente con PRIMARY KEY

Regla práctica: Toda columna usada en ON ... = ... de un JOIN debería tener índice.
Las FK suelen necesitar índice explícito en MySQL.

Transacción 1: Registro de Pedido + Descuento de Stock
START TRANSACTION;

-- Paso 1: Registrar el pedido
INSERT INTO pedidos (fecha_pedido, total, estado, id_cliente)
VALUES (CURDATE(), 85000.00, 'pendiente', 3);

SET @nuevo_pedido = LAST_INSERT_ID();

-- Paso 2: Registrar los ítems
INSERT INTO order_items (id_pedido, id_producto, cantidad, precio_unitario)
VALUES (@nuevo_pedido, 1, 1, 45000.00),
       (@nuevo_pedido, 2, 3, 12000.00);

-- Paso 3: Descontar el stock
UPDATE productos SET stock = stock - 1 WHERE id_producto = 1;
UPDATE productos SET stock = stock - 3 WHERE id_producto = 2;

-- Si todo salió bien, confirmar
COMMIT;

Transacción con ROLLBACK: Simulando un Fallo
START TRANSACTION;

INSERT INTO pedidos (fecha_pedido, total, estado, id_cliente)
VALUES (CURDATE(), 45000.00, 'pendiente', 1);

SET @id_pedido = LAST_INSERT_ID();

-- Verificar que el producto tiene stock suficiente
SELECT stock INTO @stock_actual FROM productos WHERE id_producto = 1;

-- Si no hay stock, cancelar toda la operación
-- (en una aplicación real, esto lo maneja el lenguaje de programación)
-- Para demostración, hacemos ROLLBACK manual:
ROLLBACK;

-- Verificar: el pedido NO debe haberse registrado
SELECT * FROM pedidos WHERE id_pedido = @id_pedido;

Transacción 2: Cancelación de Pedido con Reembolso de Stock
START TRANSACTION;

-- Cambiar estado del pedido a 'cancelado'
UPDATE pedidos
SET estado = 'cancelado'
WHERE id_pedido = 5;

-- Devolver el stock de todos los ítems del pedido
UPDATE productos pr
INNER JOIN order_items oi ON pr.id_producto = oi.id_producto
SET pr.stock = pr.stock + oi.cantidad
WHERE oi.id_pedido = 5;

-- Registrar la devolución
INSERT INTO devoluciones (fecha, motivo, monto, id_pedido)
VALUES (CURDATE(), 'Cancelación solicitada por cliente', 85000.00, 5);

COMMIT;

SAVEPOINT: Puntos de Control Intermedios
START TRANSACTION;

INSERT INTO pedidos (...) VALUES (...);
SAVEPOINT despues_de_pedido;

INSERT INTO order_items (...) VALUES (...);
SAVEPOINT despues_de_items;

-- Si falla el descuento de stock, volver solo a este punto
UPDATE productos SET stock = stock - 1 WHERE id_producto = 1;

-- Si detectamos un problema aquí:
ROLLBACK TO SAVEPOINT despues_de_items;
-- Solo se deshace lo que vino después de ese savepoint

COMMIT;

3 Instrucciones

3.1 Transacción 1: Registro de Pedido con Descuento de Stock (40 min)
Implementa la transacción completa para registrar un nuevo pedido:
Pasos que debe incluir: 1. Registrar el pedido en pedidos. 2. Registrar cada ítem en order_items. 3. Descontar el stock correspondiente en productos. 4. Si todo es exitoso → COMMIT. 5. Si algo falla (por ejemplo, stock insuficiente) → ROLLBACK.
START TRANSACTION;

-- Paso 1: Registrar el pedido
INSERT INTO pedidos (fecha_pedido, total, estado, id_cliente, id_repartidor)
VALUES (CURDATE(), 57000.00, 'pendiente', 3, 2);

SET @id_nuevo_pedido = LAST_INSERT_ID();

-- Paso 2: Registrar ítems
INSERT INTO order_items (id_pedido, id_producto, cantidad, precio_unitario)
VALUES (@id_nuevo_pedido, 1, 1, 45000.00),
       (@id_nuevo_pedido, 3, 1, 12000.00);

-- Paso 3: Descontar stock
UPDATE productos SET stock = stock - 1 WHERE id_producto = 1;
UPDATE productos SET stock = stock - 1 WHERE id_producto = 3;

-- Verificar: mostrar el stock actualizado ANTES del COMMIT
SELECT id_producto, nombre, stock FROM productos WHERE id_producto IN (1, 3);

-- Si todo está correcto, confirmar
COMMIT;

-- Verificar: el pedido debe existir y el stock debe estar actualizado
SELECT * FROM pedidos WHERE id_pedido = @id_nuevo_pedido;
SELECT id_producto, nombre, stock FROM productos WHERE id_producto IN (1, 3);
Parte de simulación de fallo:
Repite la transacción pero esta vez agrega un ROLLBACK en lugar del COMMIT (simulando un fallo del servidor). Verifica que: - El pedido NO fue registrado. - El stock NO fue modificado.
START TRANSACTION;

INSERT INTO pedidos (fecha_pedido, total, estado, id_cliente)
VALUES (CURDATE(), 38000.00, 'pendiente', 4);

SET @id_pedido_prueba = LAST_INSERT_ID();

INSERT INTO order_items (id_pedido, id_producto, cantidad, precio_unitario)
VALUES (@id_pedido_prueba, 5, 1, 35000.00),
       (@id_pedido_prueba, 9, 1, 6500.00);

UPDATE productos SET stock = stock - 1 WHERE id_producto IN (5, 9);

-- SIMULACIÓN DE FALLO: en lugar de COMMIT, hacemos ROLLBACK
ROLLBACK;

-- Verificar que no quedaron registros residuales
SELECT * FROM pedidos WHERE id_pedido = @id_pedido_prueba;



3.2 Transacción 2: Actualización de Estado de Entrega (30 min)
Cuando un repartidor confirma la entrega, el sistema debe: 1. Actualizar el estado del pedido a 'entregado'. 2. Registrar la fecha de entrega (si tienes esa columna) o solo verificar el estado.
START TRANSACTION;

-- Verificar que el pedido existe y está en estado correcto para ser entregado
SELECT id_pedido, estado FROM pedidos WHERE id_pedido = 5;

-- Actualizar estado
UPDATE pedidos
SET estado = 'entregado'
WHERE id_pedido = 5
  AND estado = 'en_camino';   -- solo actualiza si estaba "en_camino"

-- Verificar cuántas filas se actualizaron (debe ser 1)
-- Si es 0, el pedido no estaba en el estado correcto → ROLLBACK
SELECT ROW_COUNT() AS filas_actualizadas;

COMMIT;



3.3 Transacción 3: Cancelación de Pedido con Reembolso de Stock (40 min)
Cuando un cliente cancela un pedido, el sistema debe: 1. Cambiar el estado del pedido a 'cancelado'. 2. Devolver el stock de todos los ítems del pedido. 3. Registrar la devolución en la tabla devoluciones.
START TRANSACTION;

-- Usar SAVEPOINT después del primer paso crítico
UPDATE pedidos SET estado = 'cancelado' WHERE id_pedido = 3;
SAVEPOINT estado_actualizado;

-- Devolver stock de todos los ítems del pedido
UPDATE productos pr
INNER JOIN order_items oi ON pr.id_producto = oi.id_producto
SET pr.stock = pr.stock + oi.cantidad
WHERE oi.id_pedido = 3;

SAVEPOINT stock_reintegrado;

-- Registrar la devolución
INSERT INTO devoluciones (fecha, motivo, monto, id_pedido)
VALUES (CURDATE(), 'Cancelación solicitada por cliente antes de despacho',
        (SELECT total FROM pedidos WHERE id_pedido = 3), 3);

COMMIT;

-- Verificar resultado completo
SELECT p.id_pedido, p.estado, p.total,
       d.id_devolucion, d.motivo
FROM pedidos p
LEFT JOIN devoluciones d ON p.id_pedido = d.id_pedido
WHERE p.id_pedido = 3;
